def eligible_for_housing_assistance(self) -> bool:
    # Check eligibility based on employment status and annual income
    if self.is_unemployed() and self.annual_income < 15000:
        return True

    # Check eligibility based on monthly rent and education level
    if self.has_low_monthly_rent() and self.is_educated():
        return True

    # Check eligibility based on marital status and race
    if self.is_single() and self.is_minority_race():
        return True

    # If none of the above conditions are met, the applicant is not eligible for housing assistance
    return False
